// Extrai dados da msg do payload Evolution (messages.upsert)
const body = $json.body || $json || {};
const event = body.event || '';
const data = body.data || {};

// Só processa messages.upsert
if (event !== 'messages.upsert' && event !== 'MESSAGES_UPSERT') {
  return [{ json: { skip: true, reason: 'evento não é messages.upsert', event } }];
}

const key = data.key || {};
const rawRemoteJid = key.remoteJid || '';
const fromMe = !!key.fromMe;
const msgId = key.id || ('id_' + Date.now() + '_' + Math.random().toString(36).slice(2));

// Ignora grupos
if (!rawRemoteJid || rawRemoteJid.includes('@g.us')) {
  return [{ json: { skip: true, reason: 'grupo' } }];
}

// Suporte a @lid (Linked Device IDs do WhatsApp moderno):
// Se remoteJid é @lid, resolve via key.remoteJidAlt (que tem o phone real
// como @s.whatsapp.net). Sem isso, todas msgs novas ficam ignoradas porque
// o WhatsApp passou a usar @lid em maioria dos pacientes.
const isLid = rawRemoteJid.endsWith('@lid');
const remoteJidAlt = (key.remoteJidAlt || '').trim();
const remoteJid = (isLid && remoteJidAlt) ? remoteJidAlt : rawRemoteJid;

if (isLid && !remoteJidAlt) {
  return [{ json: { skip: true, reason: 'lid sem remoteJidAlt' } }];
}

const phone = remoteJid.replace('@s.whatsapp.net', '');

// Tipo de msg
const m = data.message || {};
let msgType = 'text';
let msgText = '';
let mediaUrl = '';
let mediaBase64 = '';
let mediaMime = '';

if (m.conversation) { msgType = 'text'; msgText = m.conversation; }
else if (m.extendedTextMessage?.text) { msgType = 'text'; msgText = m.extendedTextMessage.text; }
else if (m.imageMessage) { msgType = 'image'; mediaUrl = m.imageMessage.url || ''; mediaBase64 = m.imageMessage.base64 || ''; mediaMime = m.imageMessage.mimetype || 'image/jpeg'; msgText = m.imageMessage.caption || ''; }
else if (m.audioMessage) { msgType = 'audio'; mediaUrl = m.audioMessage.url || ''; mediaBase64 = m.audioMessage.base64 || ''; mediaMime = m.audioMessage.mimetype || 'audio/ogg'; }
else if (m.videoMessage) { msgType = 'video'; mediaUrl = m.videoMessage.url || ''; msgText = m.videoMessage.caption || ''; }
else if (m.documentMessage) { msgType = 'document'; mediaUrl = m.documentMessage.url || ''; msgText = m.documentMessage.fileName || ''; }
else { msgType = 'unknown'; }

// Ignora msgs do próprio chip (fromMe=true) — agente não responde a si mesmo
if (fromMe) {
  return [{ json: { skip: true, reason: 'fromMe=true', phone, msgId } }];
}

return [{
  json: {
    skip: false,
    phone,
    remoteJid,
    rawRemoteJid,
    isLid,
    msgId,
    fromMe,
    msgType,
    msgText,
    mediaUrl,
    mediaBase64,
    mediaMime,
    pushName: data.pushName || '',
    instanceName: body.instance || 'Consultorio',
    timestamp: Date.now(),
  }
}];

// Guarda id da msg enfileirada pra owner check depois
const enfileirado = Array.isArray($json) ? $json[0] : $json;
const normalizado = $('Normalizar payload').item.json;
return [{
  json: {
    ...normalizado,
    queue_msg_id: enfileirado.id,
    queued_at: enfileirado.created_at,
  }
}];

// Sou o dono? Sim = a msg enfileirada é a última (ou não há mais recente).
// Agrego texto de todas msgs na fila pra passar pro agente.
const payload = $('Guardar queue_msg_id').item.json;
const rows = Array.isArray($json) ? $json : [];

if (!rows || rows.length === 0) {
  return [{ json: { ...payload, skip: true, reason: 'fila vazia após wait' } }];
}

// Última msg (já ordenada ASC, pega a última)
const last = rows[rows.length - 1];
if (last.id !== payload.queue_msg_id) {
  return [{ json: { ...payload, skip: true, reason: 'não sou o dono, outra msg chegou' } }];
}

// Agrega texto das msgs (pela ordem ASC)
const textos = rows
  .map(r => (r.text || '').trim())
  .filter(t => t && t !== '📷 Imagem' && t !== '🎤 Áudio')
  .join('\n');

// Tipo da última msg
const lastType = last.message_type || 'text';
const lastMedia = last.media_url || '';

return [{
  json: {
    ...payload,
    skip: false,
    aggregated_text: textos || '',
    last_msg_type: lastType,
    last_media_url: lastMedia,
    queue_rows_count: rows.length,
  }
}];

// Transcreve áudio via OpenAI Whisper. Roda só se msg é áudio.
const payload = $json;
if (payload.last_msg_type !== 'audio') {
  return [{ json: { ...payload, transcricao: '' } }];
}

const openaiKey = $env.OPENAI_API_KEY;
if (!openaiKey) {
  return [{ json: { ...payload, transcricao: '[Whisper: OPENAI_API_KEY ausente]' } }];
}

// Se tem base64, usa. Senão tenta download da URL.
let audioBytes;
if (payload.mediaBase64) {
  audioBytes = Uint8Array.from(atob(payload.mediaBase64), c => c.charCodeAt(0));
} else if (payload.last_media_url || payload.mediaUrl) {
  const r = await fetch(payload.last_media_url || payload.mediaUrl);
  if (!r.ok) return [{ json: { ...payload, transcricao: '[Whisper: falha download]' } }];
  audioBytes = new Uint8Array(await r.arrayBuffer());
} else {
  return [{ json: { ...payload, transcricao: '[Whisper: sem áudio]' } }];
}

const blob = new Blob([audioBytes], { type: payload.mediaMime || 'audio/ogg' });
const form = new FormData();
form.append('file', blob, 'audio.ogg');
form.append('model', 'whisper-1');
form.append('language', 'pt');

const r = await fetch('https://api.openai.com/v1/audio/transcriptions', {
  method: 'POST',
  headers: { Authorization: 'Bearer ' + openaiKey },
  body: form,
});
if (!r.ok) {
  const t = await r.text().catch(() => '');
  return [{ json: { ...payload, transcricao: '[Whisper erro: ' + r.status + ']' } }];
}
const j = await r.json();
return [{ json: { ...payload, transcricao: j.text || '' } }];

// Descreve imagem via Gemini Vision. Roda depois do Whisper (pass-through se não é imagem).
const payload = $json;
if (payload.last_msg_type !== 'image') {
  return [{ json: { ...payload, analise_imagem: '' } }];
}

const geminiKey = $env.GEMINI_API_KEY;
if (!geminiKey) {
  return [{ json: { ...payload, analise_imagem: '[Vision: GEMINI_API_KEY ausente]' } }];
}

const mime = payload.mediaMime || 'image/jpeg';
let b64 = payload.mediaBase64 || '';
if (!b64 && (payload.last_media_url || payload.mediaUrl)) {
  const r = await fetch(payload.last_media_url || payload.mediaUrl);
  if (!r.ok) return [{ json: { ...payload, analise_imagem: '[Vision: falha download]' } }];
  const bytes = new Uint8Array(await r.arrayBuffer());
  b64 = btoa(String.fromCharCode(...bytes));
}
if (!b64) return [{ json: { ...payload, analise_imagem: '[Vision: sem imagem]' } }];

const r = await fetch('https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'x-goog-api-key': geminiKey },
  body: JSON.stringify({
    contents: [{
      role: 'user',
      parts: [
        { text: 'Descreva essa imagem em português, de forma objetiva, em 1-2 frases. Se for documento médico, ferida, medicamento, receita ou exame, extraia dados visíveis (números, nomes, valores).' },
        { inline_data: { mime_type: mime, data: b64 } }
      ]
    }],
    generationConfig: { temperature: 0.2, maxOutputTokens: 300 }
  })
});
if (!r.ok) return [{ json: { ...payload, analise_imagem: '[Vision erro: ' + r.status + ']' } }];
const j = await r.json();
const desc = j?.candidates?.[0]?.content?.parts?.[0]?.text || '';
return [{ json: { ...payload, analise_imagem: desc } }];

// Parse response Gemini
const payload = $('Montar prompt').item.json;
const raw = $json;
const text = raw?.candidates?.[0]?.content?.parts?.[0]?.text || '';

let parsed;
try {
  const clean = text.replace(/^```json\s*/i, '').replace(/```$/, '').trim();
  parsed = JSON.parse(clean);
} catch (e) {
  return [{ json: { ...payload, erro: 'JSON inválido Gemini', raw: text.slice(0, 300) } }];
}

return [{
  json: {
    ...payload,
    ia_messages: Array.isArray(parsed.messages) && parsed.messages.length ? parsed.messages : ['Desculpe, não consegui processar. Vou verificar com o Dr. Maikon.'],
    DISPARAR_ALERTA: !!parsed.DISPARAR_ALERTA,
    alerta_resumo: parsed.alerta_resumo || '',
    PRECISA_MAIKON: !!parsed.PRECISA_MAIKON,
    duvida_maikon: parsed.duvida_maikon || '',
  }
}];

// Envia msgs IA com typing+delay, dispara alertas se preciso, salva histórico.
const p = $json;
const evoBase = $env.EVOLUTION_API_URL;
const evoKey = $env.EVOLUTION_API_KEY;
const instance = p.instanceName || 'Consultorio';
const httpRequest = this.helpers.httpRequest.bind(this.helpers);

function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

async function evo(path, body) {
  try {
    const resp = await httpRequest({
      method: 'POST', url: evoBase + path,
      headers: { 'Content-Type': 'application/json', apikey: evoKey },
      body, json: true, returnFullResponse: true, timeout: 15000,
    });
    return { ok: resp.statusCode >= 200 && resp.statusCode < 300, status: resp.statusCode, body: resp.body };
  } catch (e) { return { ok: false, err: String(e && e.message || e).slice(0, 200) }; }
}

const phone = p.phone;
const msgs = p.ia_messages || [];
const resultados = [];

for (let i = 0; i < msgs.length; i++) {
  const txt = msgs[i];
  if (!txt) continue;
  const delay = Math.max(1500, Math.min(4500, txt.length * 60));
  await evo('/chat/sendPresence/' + encodeURIComponent(instance), { number: phone, presence: 'composing', delay });
  await sleep(delay);
  const r = await evo('/message/sendText/' + encodeURIComponent(instance), { number: phone, text: txt });
  resultados.push({ to: 'paciente', text: txt, ok: r.ok, status: r.status });
  if (i < msgs.length - 1) await sleep(900 + Math.random() * 1500);
}

// Alerta urgente (DISPARAR_ALERTA) → Dr Maikon + Isadora + Raul
let alerta_enviado = false;
if (p.DISPARAR_ALERTA) {
  const alertaTxt = '🚨 *ALERTA PACIENTE PÓS-OP*\n\n' +
    'Telefone: ' + p.phone + '\n' +
    'Nome: ' + (p.pushName || '(não informado)') + '\n\n' +
    'Resumo: ' + (p.alerta_resumo || 'sem resumo') + '\n\n' +
    'Última msg do paciente: "' + ((p.aggregated_text || '').slice(0, 200)) + '"';
  for (const destino of ['554792153480', '554799486377', '5554984351512']) {
    if (destino === phone) continue;
    const rA = await evo('/message/sendText/' + encodeURIComponent(instance), { number: destino, text: alertaTxt });
    resultados.push({ to: 'alerta', destino, ok: rA.ok });
    if (rA.ok) alerta_enviado = true;
    await sleep(600);
  }
}

// Dúvida pro Maikon (PRECISA_MAIKON)
let duvida_salva = false;
if (p.PRECISA_MAIKON && p.duvida_maikon) {
  try {
    const supaUrl = $env.SUPABASE_URL;
    const supaKey = $env.SUPABASE_SERVICE_ROLE_KEY;
    const refChars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
    let ref = '';
    for (let i = 0; i < 4; i++) ref += refChars[Math.floor(Math.random() * refChars.length)];

    await httpRequest({
      method: 'POST', url: supaUrl + '/rest/v1/consultorio_duvidas',
      headers: { apikey: supaKey, Authorization: 'Bearer ' + supaKey, 'Content-Type': 'application/json', Prefer: 'return=minimal' },
      body: { phone, nome_paciente: p.pushName || null, pergunta: p.duvida_maikon, ref_id: ref, status: 'pendente' },
      json: true,
    });
    duvida_salva = true;
    resultados.push({ to: 'duvida_salva', ref });

    const duvidaTxt = '❓ *Dúvida de paciente pós-op*\n\n' +
      'Paciente: ' + (p.pushName || p.phone) + '\n' +
      'Ref: ' + ref + '\n\n' +
      p.duvida_maikon + '\n\n' +
      'Responda aqui mesmo com "Ref ' + ref + ': <sua resposta>" que eu repasso ao paciente.';
    await evo('/message/sendText/' + encodeURIComponent(instance), { number: '554792153480', text: duvidaTxt });
  } catch (e) { resultados.push({ to: 'duvida_erro', err: String(e).slice(0, 200) }); }
}

// Salva histórico + limpa fila
try {
  const supaUrl = $env.SUPABASE_URL;
  const supaKey = $env.SUPABASE_SERVICE_ROLE_KEY;
  const histRows = [];
  if (p._finalMsg) histRows.push({ phone, nome_paciente: p.pushName || null, role: 'paciente', text: p._finalMsg });
  for (const m of msgs) histRows.push({ phone, nome_paciente: p.pushName || null, role: 'ia', text: m });
  if (histRows.length) {
    await httpRequest({
      method: 'POST', url: supaUrl + '/rest/v1/consultorio_historico',
      headers: { apikey: supaKey, Authorization: 'Bearer ' + supaKey, 'Content-Type': 'application/json', Prefer: 'return=minimal' },
      body: histRows, json: true,
    });
  }
  await httpRequest({
    method: 'DELETE', url: supaUrl + '/rest/v1/consultorio_fila_msgs?phone=eq.' + encodeURIComponent(phone),
    headers: { apikey: supaKey, Authorization: 'Bearer ' + supaKey, Prefer: 'return=minimal' },
  });
} catch (e) { resultados.push({ to: 'hist_erro', err: String(e).slice(0, 200) }); }

return [{ json: { ...p, resultados, alerta_enviado, duvida_salva, total_enviadas: resultados.filter(r => r.to === 'paciente' && r.ok).length } }];
